// Sistem çağrısı örneği (C)
#include <unistd.h>
#include <fcntl.h>

int main() {
    // open() sistem çağrısı
    int fd = open("/tmp/test.txt", O_RDONLY);

    if (fd == -1) {
        perror("open failed");
        return 1;
    }

    char buffer[100];
    // read() sistem çağrısı
    ssize_t bytes = read(fd, buffer, sizeof(buffer));

    // write() sistem çağrısı (stdout)
    write(STDOUT_FILENO, buffer, bytes);

    // close() sistem çağrısı
    close(fd);

    return 0;
}

