// Sistem çağrısı performansı
#include <sys/time.h>
#include <unistd.h>
#include <stdio.h>

void measure_syscall() {
    struct timeval start, end;

    gettimeofday(&start, NULL);

    // 1 milyon kez getpid() çağır
    for (int i = 0; i < 1000000; i++) {
        getpid();  // Basit sistem çağrısı
    }

    gettimeofday(&end, NULL);

    long seconds = end.tv_sec - start.tv_sec;
    long micros = end.tv_usec - start.tv_usec;
    long elapsed = seconds * 1000000 + micros;

    printf("1M syscalls: %ld microseconds\n", elapsed);
    printf("Per syscall: %.2f nanoseconds\n",
           (elapsed * 1000.0) / 1000000);
}

int main() {
    measure_syscall();
    return 0;
}

