// Virtual memory layout (Linux)
#include <stdio.h>
#include <stdlib.h>
#include <unistd.h>

int global_var = 42;  // Data segment
int uninitialized;    // BSS segment

void print_addresses() {
    int stack_var = 10;  // Stack
    int *heap_var = malloc(sizeof(int));  // Heap
    *heap_var = 20;

    printf("Text (code):   %p\n", (void*)print_addresses);
    printf("Global data:   %p\n", (void*)&global_var);
    printf("BSS:           %p\n", (void*)&uninitialized);
    printf("Heap:          %p\n", (void*)heap_var);
    printf("Stack:         %p\n", (void*)&stack_var);

    free(heap_var);
}

int main() {
    print_addresses();

    // /proc/self/maps ile memory map'i gör
    system("cat /proc/self/maps");

    return 0;
}

// Page fault istatistikleri
#include <sys/resource.h>
#include <stdio.h>
#include <stdlib.h>

void cause_page_faults() {
    // Büyük bellek allocate et
    size_t size = 100 * 1024 * 1024;  // 100 MB
    char *memory = malloc(size);

    struct rusage usage_before, usage_after;
    getrusage(RUSAGE_SELF, &usage_before);

    // Belleğe eriş (page fault'lar oluşur)
    for (size_t i = 0; i < size; i += 4096) {
        memory[i] = 1;  // Her sayfaya dokunarak yükle
    }

    getrusage(RUSAGE_SELF, &usage_after);

    long minor_faults = usage_after.ru_minflt -
                       usage_before.ru_minflt;
    long major_faults = usage_after.ru_majflt -
                       usage_before.ru_majflt;

    printf("Minor page faults: %ld\n", minor_faults);
    printf("Major page faults: %ld\n", major_faults);

    free(memory);
}

// Heap allocation ve leak detection
#include <stdlib.h>
#include <stdio.h>

void memory_leak_example() {
    int *ptr = malloc(100 * sizeof(int));
    // free(ptr);  // Unutuldu - memory leak!
}

void correct_usage() {
    int *ptr = malloc(100 * sizeof(int));
    if (ptr == NULL) {
        fprintf(stderr, "Allocation failed\n");
        return;
    }

    // Belleği kullan
    for (int i = 0; i < 100; i++) {
        ptr[i] = i;
    }

    free(ptr);  // Doğru kullanım
}

int main() {
    memory_leak_example();
    correct_usage();
    return 0;
}

