// Memory-mapped file örneği
#include <sys/mman.h>
#include <sys/stat.h>
#include <fcntl.h>
#include <stdio.h>
#include <unistd.h>

int main() {
    // Dosyayı aç
    int fd = open("data.txt", O_RDWR);
    if (fd == -1) {
        perror("open");
        return 1;
    }

    // Dosya boyutunu al
    struct stat sb;
    fstat(fd, &sb);

    // Dosyayı map et
    char *mapped = mmap(NULL, sb.st_size,
                       PROT_READ | PROT_WRITE,
                       MAP_SHARED, fd, 0);

    if (mapped == MAP_FAILED) {
        perror("mmap");
        close(fd);
        return 1;
    }

    // Bellek gibi eriş
    printf("First char: %c\n", mapped[0]);
    mapped[0] = 'X';  // Dosyayı değiştir

    // Unmap
    munmap(mapped, sb.st_size);
    close(fd);

    return 0;
}

// İnode bilgilerini görüntüleme
#include <sys/stat.h>
#include <stdio.h>
#include <time.h>

void print_file_info(const char *path) {
    struct stat st;

    if (stat(path, &st) == -1) {
        perror("stat");
        return;
    }

    printf("File: %s\n", path);
    printf("Inode: %lu\n", st.st_ino);
    printf("Size: %ld bytes\n", st.st_size);
    printf("Blocks: %ld\n", st.st_blocks);
    printf("Block size: %ld\n", st.st_blksize);
    printf("Links: %lu\n", st.st_nlink);
    printf("Mode: %o\n", st.st_mode & 0777);

    printf("Access time: %s", ctime(&st.st_atime));
    printf("Modify time: %s", ctime(&st.st_mtime));
    printf("Change time: %s", ctime(&st.st_ctime));
}

int main() {
    print_file_info("/etc/passwd");
    return 0;
}

// Link oluşturma
#include <unistd.h>
#include <stdio.h>

int main() {
    // Hard link oluştur
    if (link("original.txt", "hardlink.txt") == -1) {
        perror("hard link failed");
    }

    // Symbolic link oluştur
    if (symlink("original.txt", "softlink.txt") == -1) {
        perror("symbolic link failed");
    }

    // Link bilgisini oku
    char buffer[256];
    ssize_t len = readlink("softlink.txt", buffer, sizeof(buffer)-1);
    if (len != -1) {
        buffer[len] = '\0';
        printf("Soft link points to: %s\n", buffer);
    }

    return 0;
}

