// Dosya izinlerini değiştirme
#include <sys/stat.h>
#include <stdio.h>

int main() {
    // chmod 755 file.txt
    if (chmod("file.txt", S_IRWXU | S_IRGRP | S_IXGRP | S_IROTH | S_IXOTH) == -1) {
        perror("chmod failed");
        return 1;
    }

    // İzinleri kontrol et
    struct stat st;
    if (stat("file.txt", &st) == 0) {
        printf("Permissions: ");
        printf((S_ISDIR(st.st_mode)) ? "d" : "-");
        printf((st.st_mode & S_IRUSR) ? "r" : "-");
        printf((st.st_mode & S_IWUSR) ? "w" : "-");
        printf((st.st_mode & S_IXUSR) ? "x" : "-");
        printf((st.st_mode & S_IRGRP) ? "r" : "-");
        printf((st.st_mode & S_IWGRP) ? "w" : "-");
        printf((st.st_mode & S_IXGRP) ? "x" : "-");
        printf((st.st_mode & S_IROTH) ? "r" : "-");
        printf((st.st_mode & S_IWOTH) ? "w" : "-");
        printf((st.st_mode & S_IXOTH) ? "x" : "-");
        printf("\n");
    }

    return 0;
}

// Disk I/O ve caching
#include <fcntl.h>
#include <unistd.h>
#include <stdio.h>
#include <time.h>

void measure_io(const char *path, int use_sync) {
    int flags = O_WRONLY | O_CREAT | O_TRUNC;
    if (use_sync) {
        flags |= O_SYNC;  // Her yazma hemen diske
    }

    int fd = open(path, flags, 0644);
    if (fd == -1) {
        perror("open");
        return;
    }

    clock_t start = clock();

    // 1000 kez 4KB yaz
    char buffer[4096] = {0};
    for (int i = 0; i < 1000; i++) {
        write(fd, buffer, sizeof(buffer));
    }

    if (!use_sync) {
        fsync(fd);  // Manuel sync
    }

    clock_t end = clock();
    double elapsed = (double)(end - start) / CLOCKS_PER_SEC;

    printf("%s: %.3f seconds\n",
           use_sync ? "O_SYNC" : "Buffered", elapsed);

    close(fd);
}

int main() {
    measure_io("/tmp/buffered.dat", 0);
    measure_io("/tmp/sync.dat", 1);
    return 0;
}
